// Ən azı bir dəfə çörək qızardırıq
let count = 1;
do {
  console.log("Çörək dilimi " + count + " qızardıldı!");
  count++;
} while (count <= 3);
// nəticə:
// Çörək dilimi 1 qızardıldı!
// Çörək dilimi 2 qızardıldı!
// Çörək dilimi 3 qızardıldı!

// Ən azı bir dəfə mesaj göstəririk
let tries = 0;
do {
  console.log("Sınaq " + tries);
  tries++;
} while (tries < 2);
// nəticə:
// Sınaq 0
// Sınaq 1

// Blok scope ilə nümunə
do {
  let message = "Bu mesaj yalnız burada işləyir!";
  console.log(message); // nəticə: Bu mesaj yalnız burada işləyir!
} while (false);
// console.log(message); // Xəta: message is not defined

// Müqayisə nümunəsi
// while ilə
let count1 = 0;
while (count1 < 2) {
  console.log("while: " + count1);
  count1++;
}
// nəticə: while: 0, while: 1

// do...while ilə
let count2 = 0;
do {
  console.log("do...while: " + count2);
  count2++;
} while (count2 < 2);
// nəticə: do...while: 0, do...while: 1

