// Toast at least one slice of bread
let count = 1;
do {
  console.log("Bread slice " + count + " toasted!");
  count++;
} while (count <= 3);
// Output:
// Bread slice 1 toasted!
// Bread slice 2 toasted!
// Bread slice 3 toasted!

// Show a message at least once
let tries = 0;
do {
  console.log("Try " + tries);
  tries++;
} while (tries < 2);
// Output:
// Try 0
// Try 1

// Block scope example
do {
  let message = "This message only works here!";
  console.log(message); // Output: This message only works here!
} while (false);
// console.log(message); // Error: message is not defined

// Comparison example
// With while
let count1 = 0;
while (count1 < 2) {
  console.log("while: " + count1);
  count1++;
}
// Output: while: 0, while: 1

// With do...while
let count2 = 0;
do {
  console.log("do...while: " + count2);
  count2++;
} while (count2 < 2);
// Output: do...while: 0, do...while: 1

