// Жарим хотя бы один ломтик хлеба
let count = 1;
do {
  console.log("Ломтик хлеба " + count + " поджарен!");
  count++;
} while (count <= 3);
// Вывод:
// Ломтик хлеба 1 поджарен!
// Ломтик хлеба 2 поджарен!
// Ломтик хлеба 3 поджарен!

// Показываем сообщение хотя бы один раз
let tries = 0;
do {
  console.log("Попытка " + tries);
  tries++;
} while (tries < 2);
// Вывод:
// Попытка 0
// Попытка 1

// Пример блочной области видимости
do {
  let message = "Это сообщение работает только здесь!";
  console.log(message); // Вывод: Это сообщение работает только здесь!
} while (false);
// console.log(message); // Ошибка: message не определена

// Пример сравнения
// С while
let count1 = 0;
while (count1 < 2) {
  console.log("while: " + count1);
  count1++;
}
// Вывод: while: 0, while: 1

// С do...while
let count2 = 0;
do {
  console.log("do...while: " + count2);
  count2++;
} while (count2 < 2);
// Вывод: do...while: 0, do...while: 1

